('spanish:9-2-the-environment-and-global-issues:mcq:a9792461', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which sentence correctly uses ‘hay que’ + infinitive?", "options": ["Hay que ahorrar agua en casa", "Hay que ahorramos agua en casa", "Hay que ahorrando agua en casa", "Hay que ahorrado agua en casa"]}'::jsonb, '{"answer": 0, "explain": "‘hay que’ must be followed by an infinitive (ahorrar), never a conjugated verb, a gerund or a past participle."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:d574249c', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Complete: ‘Para proteger el medio ambiente, hay que ___ menos electricidad.’", "options": ["usar", "uso", "usando", "usado"]}'::jsonb, '{"answer": 0, "explain": "‘hay que’ takes an infinitive → usar. The others are the noun, the gerund and the past participle."}'::jsonb),
