('spanish:9-2-the-environment-and-global-issues:mcq:144c390c', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''a citizen''?", "options": ["un ciudadano", "un vecino", "una población", "un país"]}'::jsonb, '{"answer": 0, "explain": "un ciudadano = a citizen. un vecino = a neighbour, una población = a population, un país = a country — all people/place words that are easy to muddle."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:6ad93f51', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''pure''?", "options": ["puro", "profundo", "seco", "eléctrico"]}'::jsonb, '{"answer": 0, "explain": "puro = pure (e.g. aire puro). profundo = deep, seco = dry, eléctrico = electric — other adjectives used to describe nature and energy."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:7ad71836', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''a degree'' (of temperature)?", "options": ["un grado", "una temperatura", "un factor", "un dato"]}'::jsonb, '{"answer": 0, "explain": "un grado = a degree. una temperatura = a temperature (a close relative, but not the same word), un factor = a factor, un dato = a piece of data."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:1a75030f', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''wood'' (the material)?", "options": ["la madera", "la piedra", "el bosque", "el cultivo"]}'::jsonb, '{"answer": 0, "explain": "la madera = wood, the material. la piedra = stone, el bosque = the forest (where wood comes from, but not the material itself), el cultivo = the crop/cultivation."}'::jsonb),
