('spanish:9-2-the-environment-and-global-issues:mcq:42ac96e9', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''to cause''?", "options": ["causar", "reflejar", "insistir", "prohibir"]}'::jsonb, '{"answer": 0, "explain": "causar = to cause (e.g. la deforestación causa problemas). reflejar = to reflect, insistir = to insist, prohibir = to forbid."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:91a4097d', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''to reflect''?", "options": ["reflejar", "insistir", "causar", "pensar"]}'::jsonb, '{"answer": 0, "explain": "reflejar = to reflect (e.g. los datos reflejan un aumento). insistir = to insist, causar = to cause, pensar = to think."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:052932d2', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''to insist''?", "options": ["insistir", "reflejar", "causar", "notar"]}'::jsonb, '{"answer": 0, "explain": "insistir = to insist (e.g. insistir en que + subjunctive). reflejar = to reflect, causar = to cause, notar = to notice."}'::jsonb),
('spanish:9-2-the-environment-and-global-issues:mcq:8a845cee', 'spanish', 'spanish:9-2-the-environment-and-global-issues', '9.2 The Environment and Global Issues', 'mcq', 'mcq', 1, '{"question": "Which word means ''to forbid''?", "options": ["prohibir", "permitir", "reflejar", "notar"]}'::jsonb, '{"answer": 0, "explain": "prohibir = to forbid. permitir = to allow (the opposite!), reflejar = to reflect, notar = to notice."}'::jsonb),
